import React from "react";

function Sidebar({
  active,
  handleMenuClick,
  chats,
  currentChatId,
  setCurrentChatId,
  newChat,
  deleteChat
}) {
  return (
    <div className="sidebar">

      <h3>Menu</h3>

      {/* MAIN MENU */}
      <div
        className={active === "chat" ? "active" : ""}
        onClick={() => handleMenuClick("chat")}
      >
        💬 Chat
      </div>

      <div
        className={active === "project" ? "active" : ""}
        onClick={() => handleMenuClick("project")}
      >
        📁 Project
      </div>

      <div
        className={active === "about" ? "active" : ""}
        onClick={() => handleMenuClick("about")}
      >
        ℹ️ About
      </div>

      <div onClick={() => handleMenuClick("metrics")}>
        📊 Metrics
      </div>

      {/* CHAT HISTORY */}
      <h3 style={{ marginTop: "20px" }}>Chats</h3>

      <button className="new-chat-btn" onClick={newChat}>
        + New Chat
      </button>

      <div className="chat-history">
        {chats.map(chat => (
          <div
            key={chat.id}
            className={`chat-item ${chat.id === currentChatId ? "active" : ""}`}
          >
            <span onClick={() => setCurrentChatId(chat.id)}>
              {chat.title}
            </span>

            <button
              className="delete-btn"
              onClick={(e) => {
                e.stopPropagation();
                deleteChat(chat.id);
              }}
            >
              🗑
            </button>
          </div>
        ))}
      </div>

    </div>
  );
}

export default Sidebar;
